
class IngressSpec {final IngressBackend? defaultBackend; final String? ingressClassName; final List<IngressRule>? rules; final List<IngressTLS>? tls; IngressSpec({this.defaultBackend, this.ingressClassName, this.rules, this.tls}); factory IngressSpec.fromJson(Map<String, dynamic> json) {return IngressSpec(defaultBackend: json['defaultBackend'] != null ? IngressBackend.fromJson(json['defaultBackend']) : null, ingressClassName: json['ingressClassName'], rules: json['rules'] != null ? (json['rules'] as List).map((e) => IngressRule.fromJson(e)).toList() : null, tls: json['tls'] != null ? (json['tls'] as List).map((e) => IngressTLS.fromJson(e)).toList() : null);} Map<String, dynamic> toJson() {return {if (defaultBackend != null) 'defaultBackend' : defaultBackend!.toJson(), if (ingressClassName != null) 'ingressClassName' : ingressClassName, if (rules != null) 'rules' : rules!.map((e) => e.toJson()).toList(), if (tls != null) 'tls' : tls!.map((e) => e.toJson()).toList()};}}
